  from datetime import date
  from collections import defaultdict

  WATER_INTAKE_FILE = 'daily_water_intake.txt'

  def load_intake_data():
      intake_data = defaultdict(float)
      try:
          with open(WATER_INTAKE_FILE, 'r') as file:
              for line in file:
                  day, liters = line.strip().split(',')
                  intake_data[date.fromisoformat(day)] = float(liters)
      except FileNotFoundError:
          pass
      return intake_data

  def save_intake_data(intake_data):
      with open(WATER_INTAKE_FILE, 'w') as file:
          for day, liters in sorted(intake_data.items()):
              file.write(f"{day.isoformat()},{liters}\n")

